we have a google cloud function hosted at 'https://us-central1-ai-fb-poster.cloudfunctions.net/api'. how do we call this from curl or our typescript google chrome extension? Here is the source code : /* eslint-disable object-curly-spacing */
/* eslint-disable @typescript-eslint/no-var-requires */
/* eslint-disable require-jsdoc */
/* eslint-disable @typescript-eslint/no-explicit-any */
import * as functions from "firebase-functions";
const fetch = require("node-fetch"); // ✅ will work correctly with v2
import express = require("express");

const app = express();

app.get("/", async (req: any, res: any) => {
  const fileUrl = req.query.url as string;

  console.log("Incoming request to /api with url:", fileUrl);

  if (!fileUrl) {
    return res.status(400).json({ error: "Missing 'url' parameter" });
  }

  try {
    const response = await fetch(fileUrl);

    if (!response.ok) {
      console.error("Fetch failed:", response.status, response.statusText);
      return res.status(response.status).send("Failed to fetch file");
    }

    res.setHeader(
      "Content-Type",
      response.headers.get("content-type") || "application/octet-stream"
    );
    res.setHeader(
      "Content-Disposition",
      `attachment; filename="${getFilename(fileUrl)}"`
    );

    if (response.body) {
      response.body.pipe(res);
    } else {
      res.status(500).send("Empty response body");
    }
  } catch (error) {
    console.error("Error fetching file:", error);
    res.status(500).json({ error: "Internal server error" });
  }
});

function getFilename(url: string): string {
  try {
    const pathname = new URL(url).pathname;
    return pathname.split("/").pop() || "downloaded-file";
  } catch {
    return "downloaded-file";
  }
}

export const api = functions.https.onRequest(app);
